import { create } from "zustand";

interface Store {
    barcode: string;
    setBarcode: () => void;
    resetBarcode: () => void;
}

interface Quantity {
    quantity: number;
    minus: (by?: number) => void;
}

export const usePOSStore = create<Store>()((set) => ({
    barcode: '',
    setBarcode: () => set((state) => ({ barcode: state.barcode })),
    resetBarcode: () => set(() => ({ barcode: '' })),
}));

export const useQuantityHandler = create<Quantity>()((set) => ({
    quantity: 1,
    minus: (by = 1) => set((state) => ({ quantity: state.quantity - by })),
}));